// Update allows overriding fields `UPDATE` values. See the CatalogModelCreateBulk.OnConflict
// documentation for more info.
func (u *CatalogModelUpsertBulk) Update(set func(*CatalogModelUpsert)) *CatalogModelUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&CatalogModelUpsert{UpdateSet: update})
	}))
	return u
}

